import{_ as a,c as n,a1 as s,o}from"./chunks/framework.BDxlaA_J.js";const u=JSON.parse('{"title":"Recon-ng Tutorial","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/3-Recon-ng.md","filePath":"categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/3-Recon-ng.md"}'),t={name:"categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/3-Recon-ng.md"};function p(i,e,r,l,c,d){return o(),n("div",null,e[0]||(e[0]=[s(`<h1 id="recon-ng-tutorial" tabindex="-1">Recon-ng Tutorial <a class="header-anchor" href="#recon-ng-tutorial" aria-label="Permalink to &quot;Recon-ng Tutorial&quot;">​</a></h1><p>Recon-ng is a web-based open-source reconnaissance tool used to extract information from a target organization and its personnel. <em>Official repository:</em><a href="https://github.com/lanmaster53/recon-ng" target="_blank" rel="noreferrer">https://github.com/lanmaster53/recon-ng</a></p><ul><li>Version: v5.0.1</li></ul><h3 id="requirements" tabindex="-1">Requirements: <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements:&quot;">​</a></h3><ul><li>Kali Linux virtual machine</li></ul><h3 id="objectives" tabindex="-1">Objectives: <a class="header-anchor" href="#objectives" aria-label="Permalink to &quot;Objectives:&quot;">​</a></h3><ul><li>How to perform network recon.</li><li>Gather hosts related to a domain.</li><li>Personal Information Gathering.</li><li>Generate a report with harvested information.</li></ul><p>Recon-ng has a look and feel similar to the Metasploit Framework, reducing the learning curve for leveraging the framework.</p><h2 id="first-steps" tabindex="-1">First steps <a class="header-anchor" href="#first-steps" aria-label="Permalink to &quot;First steps&quot;">​</a></h2><ol><li>Open the terminal and type <code>recon-ng</code></li><li>Type <code>help</code> to view all commands that allow you to add/delete records to DB, query, etc.</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>back            Exits the current context</span></span>
<span class="line"><span>dashboard       Displays a summary of activity</span></span>
<span class="line"><span>db              Interfaces with the workspace&#39;s database</span></span>
<span class="line"><span>exit            Exits the framework</span></span>
<span class="line"><span>help            Displays this menu</span></span>
<span class="line"><span>index           Creates a module index (dev only)</span></span>
<span class="line"><span>keys            Manages third party resource credentials</span></span>
<span class="line"><span>marketplace     Interfaces with the module marketplace</span></span>
<span class="line"><span>modules         Interfaces with installed modules</span></span>
<span class="line"><span>options         Manages the current context options</span></span>
<span class="line"><span>pdb             Starts a Python Debugger session (dev only)</span></span>
<span class="line"><span>script          Records and executes command scripts</span></span>
<span class="line"><span>shell           Executes shell commands</span></span>
<span class="line"><span>show            Shows various framework items</span></span>
<span class="line"><span>snapshots       Manages workspace snapshots</span></span>
<span class="line"><span>spool           Spools output to a file</span></span>
<span class="line"><span>workspaces      Manages workspaces</span></span></code></pre></div><p><strong>Note: On your first load of recon-ng note the message below. You begin with an empty framework (without modules pre-installed).</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[*] No modules enabled/installed.</span></span></code></pre></div><ol start="3"><li><p>Create a new workspace: <code>workspaces create CEH</code></p></li><li><p>Add the target domain to perform a network recon: <code>db insert domains</code><code>certifiedhacker.com</code></p></li></ol><p>You can view the added domain by typing <code>show domains</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[recon-ng][CEH] &gt; db insert domains</span></span>
<span class="line"><span>domain (TEXT): certifiedhacker.com</span></span>
<span class="line"><span>[*] 1 rows affected.</span></span>
<span class="line"><span>[recon-ng][CEH] &gt; show domains</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  +--------------------------------------------+</span></span>
<span class="line"><span>  | rowid |        domain       |    module    |</span></span>
<span class="line"><span>  +--------------------------------------------+</span></span>
<span class="line"><span>  | 1     | certifiedhacker.com | user_defined |</span></span>
<span class="line"><span>  +--------------------------------------------+</span></span></code></pre></div><h2 id="using-modules-from-recon-ng-marketplace" tabindex="-1">Using Modules from Recon-ng Marketplace <a class="header-anchor" href="#using-modules-from-recon-ng-marketplace" aria-label="Permalink to &quot;Using Modules from Recon-ng Marketplace&quot;">​</a></h2><p>Recon-ng works with independent modules, database interaction, built in convenience functions, interactive help, and command completion, Recon-ng provides a powerful environment in which open source web-based reconnaissance can be conducted quickly and thoroughly. To add new modules you will use <strong>marketplace</strong>.</p><p>Recon-ng Marketplace repository: <a href="https://github.com/lanmaster53/recon-ng-marketplace" target="_blank" rel="noreferrer">https://github.com/lanmaster53/recon-ng-marketplace</a></p><p>To view the entire marketplace repo type: <code>marketplace search</code></p><p>Dealing with modules and workspaces process is very easy as shown on the example below:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>0. Installing module using marketplace command:</span></span>
<span class="line"><span>&gt; marketplace install recon/domains-hosts/findsubdomains</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. Loading the module using modules load command:</span></span>
<span class="line"><span>&gt; modules load /recon/domains-hosts/findsubdomains</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. To show module options:</span></span>
<span class="line"><span>&gt; info </span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. Executing the module:</span></span>
<span class="line"><span>&gt; run</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. To switch between modules or workspaces type:</span></span>
<span class="line"><span>&gt; back</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. Select an existing workspace:</span></span>
<span class="line"><span>&gt; workspaces select W0rkspaceName </span></span>
<span class="line"><span></span></span>
<span class="line"><span>6. Select an installed module:</span></span>
<span class="line"><span>&gt; modules load path/to/module-name</span></span></code></pre></div><h2 id="using-hackertarget-to-find-sub-domains" tabindex="-1">Using hackertarget to find sub-domains <a class="header-anchor" href="#using-hackertarget-to-find-sub-domains" aria-label="Permalink to &quot;Using hackertarget to find sub-domains&quot;">​</a></h2><p>You can find another modules to gather some subdomains, we will use hackertarget on this tutorial.</p><p>Let&#39;s install and load it: <code>marketplace install hackertarget</code><code>modules load hackertarget</code></p><p>Type <code>info</code> to view the SOURCE, currently set at default as show below: <code>info</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Name    Current Value  Required  Description</span></span>
<span class="line"><span>------  -------------  --------  -----------</span></span>
<span class="line"><span>SOURCE  default        yes       source of input (see &#39;show info&#39; for details)</span></span></code></pre></div><p>Now set the SOURCE to:</p><p><code>options set SOURCE certifiedhacker.com</code></p><p>You can use the <code>input</code> command to see the target:</p><p><code>input</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>+---------------------+</span></span>
<span class="line"><span>|    Module Inputs    |</span></span>
<span class="line"><span>+---------------------+</span></span>
<span class="line"><span>| certifiedhacker.com |</span></span>
<span class="line"><span>+---------------------+</span></span></code></pre></div><p>Run the module:</p><p><code>run</code></p><p><strong>Note: If your response is working properly but messy with a bunch of queries and values, just type <code>show hosts</code> to populate a better output.</strong></p><p><code>show hosts</code> ... <em>(This command will show a clean summary of resources discovered)</em></p><h2 id="brute-forcing-hostnames" tabindex="-1">Brute-forcing hostnames <a class="header-anchor" href="#brute-forcing-hostnames" aria-label="Permalink to &quot;Brute-forcing hostnames&quot;">​</a></h2><p>You can use another modules to harvest more hosts, such as <strong>brute_hosts</strong>.</p><p><strong>Exit</strong> your current module:</p><p><code>back</code></p><p>Install the <strong>brute_hosts</strong> module:</p><p><code>marketplace install recon/domain-hosts/brute_hosts</code></p><p>Load the module:</p><p><code>modules load recon/domain-hosts/brute_hosts</code></p><p>Set the SOURCE to target domain:</p><p><code>options set SOURCE certifiedhacker.com</code></p><p>By typing <code>info</code> you can see on this particular module, you can set your own hostnames wordlist. I recommend to use the default one that is pretty good.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Name      Current Value                 </span></span>
<span class="line"><span>  --------  -------------  </span></span>
<span class="line"><span>  SOURCE    certifiedhacker.com         </span></span>
<span class="line"><span>  WORDLIST  /root/.recon-ng/data/hostnames.txt</span></span></code></pre></div><ol start="5"><li>Run the module: <code>run</code> ... <em>(keep in mind that will take a while)</em></li></ol><h2 id="generate-a-report" tabindex="-1">Generate a report <a class="header-anchor" href="#generate-a-report" aria-label="Permalink to &quot;Generate a report&quot;">​</a></h2><p>Now that you have harvested a number of hosts, you will prepare a report containing all the information.</p><p>Install the <strong>reporting module</strong> to report in html format.</p><p><code>marketplace install reporting/html</code></p><p><strong>Note:</strong> You can install any of these modules below to export in different formats.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>reporting/csv</span></span>
<span class="line"><span>reporting/html</span></span>
<span class="line"><span>reporting/json</span></span>
<span class="line"><span>reporting/list</span></span>
<span class="line"><span>reporting/proxifier</span></span>
<span class="line"><span>reporting/pushpin</span></span>
<span class="line"><span>reporting/xlsx</span></span>
<span class="line"><span>reporting/xml</span></span></code></pre></div><p>Load the module:</p><p><code>modules load reporting/html</code></p><p>To configure the reporting information, type <code>info</code> to see the values.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span> Name      Current Value                                </span></span>
<span class="line"><span> --------  -------------                                </span></span>
<span class="line"><span> CREATOR                                   </span></span>
<span class="line"><span> CUSTOMER  </span></span>
<span class="line"><span> FILENAME  /root/.recon-ng/workspaces/CEH/results.html</span></span>
<span class="line"><span> SANITIZE  True</span></span></code></pre></div><p>You will need to assign these values, CREATOR, CUSTOMER and FILENAME.</p><p>Set your name[CREATOR], customer name[CUSTOMER], path to export and the file name[FILENAME].</p><p><code>options set CREATOR J0nDoe</code><code>options set CUSTOMER CertifiedHacker Network</code><code>options set FILENAME /root/Desktop/CE-Results.html</code></p><p>Run the module to export:</p><p><code>run</code></p><p><strong>The generated report is saved to to the Desktop.</strong></p><p>There is not much in this report, but when you start running multiple modules and add in geolocation reports can get very complex. Recon-ng does a great job keeping track of everything.</p><h1 id="using-recon-ng-to-gather-personnel-information-part-2" tabindex="-1">Using Recon-ng to Gather Personnel Information (part 2) <a class="header-anchor" href="#using-recon-ng-to-gather-personnel-information-part-2" aria-label="Permalink to &quot;Using Recon-ng to Gather Personnel Information (part 2)&quot;">​</a></h1><p>Objectives:</p><ul><li>Obtain contacts of personnel working in a organization.</li><li>Find the existence of user profiles on varios websites.</li></ul><p><strong>Important note:</strong> The <strong>location</strong> and <strong>pushpin modules</strong> mentioned in this tutorial require a valid API key to use and have some GDPR implications about data collection. Some require you to pay money, which will be mentioned below. I suggest as you go along, you save all the API keys to a file so you can use them later. To setup an API key to your recon-ng is very simple, just follow the document below, and manage your keys inside Recon-ng using: <code>keys</code> command. <a href="https://github.com/Raikia/Recon-NG-API-Key-Creation/blob/master/README-v4.8.3.md" target="_blank" rel="noreferrer">https://github.com/Raikia/Recon-NG-API-Key-Creation/blob/master/README-v4.8.3.md</a></p><h2 id="personal-information-gathering" tabindex="-1">Personal Information Gathering <a class="header-anchor" href="#personal-information-gathering" aria-label="Permalink to &quot;Personal Information Gathering&quot;">​</a></h2><p>Gathering personal information involves discovering contact details such as email, address, etc. present on target organization&#39;s web site. The Recon-ng contains various modules for haversting and discovering contact information about a certain company. Some Recon-ng modules for discovering personal information are:</p><ul><li>recon/domain-contacts</li><li>recon/companies-contacts</li><li>recon/domain-contacts/namechk</li></ul><h2 id="setup-your-recon-ng" tabindex="-1">Setup your Recon-ng <a class="header-anchor" href="#setup-your-recon-ng" aria-label="Permalink to &quot;Setup your Recon-ng&quot;">​</a></h2><ol><li>Boot your Kali Linux and open the terminal.</li><li>Type <code>recon-ng</code> to launch the application.</li><li>Add a new workspace named recon:</li></ol><p><code>workspaces create recon</code></p><h2 id="gather-contacts-associated-with-a-domain" tabindex="-1">Gather contacts associated with a domain <a class="header-anchor" href="#gather-contacts-associated-with-a-domain" aria-label="Permalink to &quot;Gather contacts associated with a domain&quot;">​</a></h2><p>Set a domain and perform footprinting on it to extract contact available in the domain.</p><p>The module selected to perform this technique uses the ARIN Whois RWS to harvest POC data from whois queries for the given domain.</p><p>Install and load the module:</p><p><code>marketplace install recon/domains-contacts/whois_pocs</code></p><p><code>modules load recon/domains-contacts/whois_pocs</code></p><p>Check the options required to run the module:</p><p><code>info</code></p><p>Set the SOURCE value to target domain:</p><p><code>options set SOURCE facebook.com</code></p><p>Run the module:</p><p><code>run</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>------------</span></span>
<span class="line"><span>FACEBOOK.COM</span></span>
<span class="line"><span>------------</span></span>
<span class="line"><span>[*] URL: http://whois.arin.net/rest/pocs;domain=facebook.com</span></span>
<span class="line"><span>[*] URL: http://whois.arin.net/rest/poc/NOL17-ARIN</span></span>
<span class="line"><span>[*] [contact] Lea Neteork ops (leigha311@facebook.com) - Whois contact</span></span>
<span class="line"><span>[*] URL: http://whois.arin.net/rest/poc/OPERA82-ARIN</span></span>
<span class="line"><span>[*] [contact] &lt;blank&gt; Operations (domain@facebook.com) - Whois contact</span></span>
<span class="line"><span>[*] URL: http://whois.arin.net/rest/poc/BST184-ARIN</span></span>
<span class="line"><span>[*] [contact] Brandon Stout (bstout@facebook.com) - Whois contact</span></span>
<span class="line"><span>[*] URL: http://whois.arin.net/rest/poc/DJW23-ARIN</span></span>
<span class="line"><span>[*] [contact] Darrell Wayne (tiffany.cameron.507@facebook.com) - Whois contact</span></span>
<span class="line"><span>[*] URL: http://whois.arin.net/rest/poc/MZU-ARIN</span></span>
<span class="line"><span>[*] [contact] Mark Zuckerberg (zuck@thefacebook.com) - Whois contact</span></span></code></pre></div><p>The output will return the contacts related to the domains.</p><h2 id="profile-existence" tabindex="-1">Profile existence <a class="header-anchor" href="#profile-existence" aria-label="Permalink to &quot;Profile existence&quot;">​</a></h2><p>The <strong>recon/profiles-profiles/namechk</strong> module validates the username existence of a specified contact, but unfortunately namechk charges to use their API.</p><p>We can search the existence of user profiles in various websites using the <strong>recon/profiles-profiles/profiler</strong>.</p><p>Type <code>back</code> to return to the workspaces home.</p><p>Install and load the module:</p><p><code>marketplace install recon/profiles-profiles/profiler</code></p><p><code>modules load recon/profiles-profiles/profiler</code></p><p>Set the SOURCE value (Target username):</p><p><code>options set SOURCE MarkZuckerberg</code></p><p>Run the module:</p><p><code>run</code></p><p>The recon/profiles-profiles/profiler module searches for this username and returns the URL of the profile in various websites (found with the matching username).</p>`,102)]))}const m=a(t,[["render",p]]);export{u as __pageData,m as default};
